def create_server(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = None,
    max_concurrent_rpcs: int = None
):
    """Create and configure the gRPC server optimized for high throughput."""

    # Auto-detect optimal worker count
    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)

    logger.info(f"Configuring server with {max_workers} workers")

    # Server options optimized for high throughput and low latency
    server_options = [
        # No message size limits
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        # Large window sizes for flow control
        ("grpc.http2.initial_connection_window_size", 64 * 1024 * 1024),  # 64MB
        ("grpc.http2.initial_window_size", 64 * 1024 * 1024),  # 64MB
        # Keep alive settings for long-lived streams
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.http2.min_time_between_pings_ms", 5000),
        ("grpc.http2.min_ping_interval_without_data_ms", 5000),
        # Large metadata limits
        ("grpc.max_metadata_size", 16 * 1024 * 1024),  # 16MB
        # Enable SO_REUSEPORT for better load distribution
        ("grpc.so_reuseport", 1),
        # Max concurrent streams per connection (unlimited effectively)
        ("grpc.max_concurrent_streams", 1000),
        # Compression
        ("grpc.default_compression_algorithm", 2),  # gzip
        ("grpc.default_compression_level", 1),  # low compression for speed
    ]

    # Create thread pool with high worker count
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker"
    )

    server = grpc.server(
        thread_pool,
        options=server_options,
        maximum_concurrent_rpcs=max_concurrent_rpcs,
        compression=grpc.Compression.Gzip
    )

    # Register servicer
    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)

    # Bind to address
    address = f"{host}:{port}"
    server.add_insecure_port(address)

    logger.info(f"Server configured on {address}")

    return server, servicer


def create_secure_server(
    host: str = "0.0.0.0",
    port: int = 50051,
    server_cert_path: str = "server.crt",
    server_key_path: str = "server.key",
    ca_cert_path: str = None,
    max_workers: int = None
):
    """Create a TLS-secured gRPC server."""

    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)

    server_options = [
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        ("grpc.http2.initial_connection_window_size", 64 * 1024 * 1024),
        ("grpc.http2.initial_window_size", 64 * 1024 * 1024),
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.max_concurrent_streams", 1000),
        ("grpc.so_reuseport", 1),
    ]

    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker"
    )

    server = grpc.server(
        thread_pool,
        options=server_options,
        compression=grpc.Compression.Gzip
    )

    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)

    # Load TLS credentials
    with open(server_key_path, "rb") as f:
        server_key = f.read()
    with open(server_cert_path, "rb") as f:
        server_cert = f.read()

    ca_cert = None
    if ca_cert_path:
        with open(ca_cert_path, "rb") as f:
            ca_cert = f.read()

    credentials = grpc.ssl_server_credentials(
        [(server_key, server_cert)],
        root_certificates=ca_cert,
        require_client_auth=ca_cert is not None
    )

    address = f"{host}:{port}"
    server.add_secure_port(address, credentials)

    logger.info(f"Secure server configured on {address}")

    return server, servicer


def run_stats_reporter(servicer: DataStreamServicer, interval: int = 30):
    """Periodically log processing statistics."""
    import threading

    def _report():
        while True:
            time.sleep(interval)
            stats = servicer._processor.stats
            logger.info(
                f"Stats - Processed: {stats['processed']}, "
                f"Errors: {stats['errors']}, "
                f"Throughput: {stats['throughput_per_sec']} msg/s, "
                f"Uptime: {stats['elapsed_seconds']}s"
            )

    thread = threading.Thread(target=_report, daemon=True, name="stats-reporter")
    thread.start()
    return thread


def serve():
    """Main entry point to start the server."""
    host = os.environ.get("GRPC_HOST", "0.0.0.0")
    port = int(os.environ.get("GRPC_PORT", "50051"))
    max_workers = int(os.environ.get("GRPC_MAX_WORKERS", "0")) or None
    use_tls = os.environ.get("GRPC_TLS", "false").lower() == "true"

    if use_tls:
        server, servicer = create_secure_server(
            host=host,
            port=port,
            server_cert_path=os.environ.get("GRPC_TLS_CERT", "server.crt"),
            server_key_path=os.environ.get("GRPC_TLS_KEY", "server.key"),
            ca_cert_path=os.environ.get("GRPC_TLS_CA", None),
            max_workers=max_workers
        )
    else:
        server, servicer = create_server(
            host=host,
            port=port,
            max_workers=max_workers
        )

    # Start stats reporter
    run_stats_reporter(servicer, interval=30)

    # Graceful shutdown handler
    shutdown_event = futures.Future()

    def _shutdown_handler(signum, frame):
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        # Give 10 seconds grace period for in-flight RPCs
        server.stop(grace=10)
        stats = servicer._processor.stats
        logger.info(f"Final stats: {stats}")
        shutdown_event.set_result(True)

    signal.signal(signal.SIGTERM, _shutdown_handler)
    signal.signal(signal.SIGINT, _shutdown_handler)

    # Start server
    server.start()
    logger.info(
        f"Data stream gRPC server started on {host}:{port} "
        f"(TLS: {use_tls})"
    )

    # Block until shutdown
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Keyboard interrupt received")
        server.stop(grace=10)

    logger.info("Server stopped")


